def nati(stem):
    last=-1
    for i,ch in enumerate(stem):
        if ch in 'रषृ': last=i
    if last<0: return False
    return not any(ch in BLOCK for ch in stem[last+1:])
def natikey(lem):
    s=lem[:-1] if (lem and lem[-1] in VS) else lem
    return nati(s)
by_lem=collections.defaultdict(list)
for lem,form,feat in rows: by_lem[lem].append((form,feat))
def lexgender(lem):
