        if 'SG' in F and 'NOM' in F:
            if form.endswith('म्'): votes['n']+=2
            elif form.endswith('ः'): votes['m']+=2
        if 'PL' in F and 'NOM' in F:
            if form.endswith(('ानि','ाणि')): votes['n']+=1
            elif form.endswith('ाः'): votes['m']+=1
        if 'DU' in F and 'NOM' in F:
            if form.endswith('े'): votes['n']+=1
            elif form.endswith('ौ'): votes['m']+=1
        if ('DAT' in F and 'SG' in F and form.endswith('्यै')) or ('GEN' in F and 'SG' in F and form.endswith('्याः')): votes['f']+=2
    if votes: return votes.most_common(1)[0][0]
    return 'f' if vc=='ा' else ('m' if vc=='a' else '?')
def femtype(lem):
    v=collections.Counter()
    for form,feat in by_lem[lem]:
        F=set(feat.split(';'))
        if 'FEM' in F and 'NOM' in F and 'SG' in F:
            if form.endswith('ी'): v['i']+=1
            elif form.endswith('ा'): v['a']+=1
    return v.most_common(1)[0][0] if v else 'a'
def variant(lem):
    # for i/ii/u/uu stems: ya-pattern vs guna vs na-insert
    v=collections.Counter()
    for form,feat in by_lem[lem]:
        F=set(feat.split(';'))
        if 'SG' in F and any(x in F for x in ('GEN','ABL','DAT','LOC')):
            if '्य' in form: v['ya']+=1
            elif 'ने' in form[-3:] or 'नि' in form[-3:] or 'नः' in form[-3:] or 'ना' in form[-3:]: v['na']+=1
