    """For a-stem adjectives: feminine formed in -I (bharatI) or -A."""
    v = collections.Counter()
    for form, feat in by_lem[lem]:
        F = set(feat.split(";"))
        if "FEM" in F and "NOM" in F and "SG" in F:
            if form.endswith("ी"):
